import markdown
from weasyprint import HTML, CSS
import re

# Read the markdown file
with open('agency-agents-research.md', 'r', encoding='utf-8') as f:
    md_content = f.read()

# Convert markdown to HTML
html_body = markdown.markdown(
    md_content,
    extensions=['tables', 'fenced_code', 'codehilite']
)

# Build full HTML document
html_doc = f"""<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<style>
body {{
    font-family: "Microsoft YaHei", "SimHei", "WenQuanYi Micro Hei", sans-serif;
    font-size: 12pt;
    line-height: 1.8;
    max-width: 800px;
    margin: 40px auto;
    padding: 20px;
    color: #222;
}}
h1 {{
    font-size: 22pt;
    color: #1a1a2e;
    border-bottom: 3px solid #1a1a2e;
    padding-bottom: 10px;
    margin-top: 30px;
}}
h2 {{
    font-size: 16pt;
    color: #16213e;
    border-left: 4px solid #16213e;
    padding-left: 10px;
    margin-top: 25px;
}}
h3 {{
    font-size: 13pt;
    color: #0f3460;
    margin-top: 20px;
}}
table {{
    border-collapse: collapse;
    width: 100%;
    margin: 15px 0;
    font-size: 10pt;
}}
th, td {{
    border: 1px solid #ccc;
    padding: 8px 12px;
    text-align: left;
}}
th {{
    background-color: #1a1a2e;
    color: white;
}}
tr:nth-child(even) {{
    background-color: #f5f5f5;
}}
blockquote {{
    border-left: 4px solid #e94560;
    margin: 15px 0;
    padding: 10px 15px;
    background: #fff9f0;
    font-style: italic;
}}
code {{
    background-color: #f4f4f4;
    padding: 2px 6px;
    border-radius: 3px;
    font-family: "Consolas", "Courier New", monospace;
    font-size: 10pt;
}}
pre {{
    background-color: #1e1e1e;
    color: #d4d4d4;
    padding: 15px;
    border-radius: 5px;
    overflow-x: auto;
    font-size: 9pt;
}}
pre code {{
    background: none;
    padding: 0;
    color: #d4d4d4;
}}
hr {{
    border: none;
    border-top: 1px solid #ddd;
    margin: 20px 0;
}}
strong {{
    color: #1a1a2e;
}}
ul, ol {{
    margin: 10px 0;
    padding-left: 25px;
}}
li {{
    margin: 5px 0;
}}
a {{
    color: #0f3460;
    text-decoration: none;
}}
.meta {{
    color: #888;
    font-size: 10pt;
    border-bottom: 1px solid #eee;
    padding-bottom: 10px;
}}
</style>
</head>
<body>
{html_body}
</body>
</html>"""

# Write HTML for debugging
with open('agency-agents-research.html', 'w', encoding='utf-8') as f:
    f.write(html_doc)

# Convert to PDF using weasyprint
HTML(string=html_doc).write_pdf('agency-agents-research.pdf')

print("PDF created successfully: agency-agents-research.pdf")
